func initShowLocalesSignal(data DataIndex) string {
	var b []byte
	b = append(b, '{')
	for i, c := range data.Catalogs {
		if i > 0 {
			b = append(b, ',')
		}
		b = append(b, c.Locale...)
		b = append(b, ':')
		if data.ShownLocales == nil {
			b = append(b, "true"...)
		} else {
			shown, ok := data.ShownLocales[c.Locale]
			if ok && shown {
				b = append(b, "true"...)
			} else {
				b = append(b, "false"...)
			}
		}
	}
	b = append(b, '}')
	return string(b)
}

// setAllLocales builds a JS expression that sets all showlocales signals
// and the shownlocales string directly (without reading DOM checkboxes).
func setAllLocales(data DataIndex, enabled bool) string {
	val := "false"
	if enabled {
		val = "true"
	}
	var b []byte
	for _, c := range data.Catalogs {
		b = append(b, "$showlocales."...)
		b = append(b, c.Locale...)
		b = append(b, '=')
		b = append(b, val...)
		b = append(b, ';')
	}
	// Build shownlocales string directly.
	b = append(b, "$shownlocales='"...)
	if enabled {
		for i, c := range data.Catalogs {
			if i > 0 {
				b = append(b, ',')
			}
			b = append(b, c.Locale...)
		}
	} else {
		b = append(b, '-')
	}
	b = append(b, '\'')
	return string(b)
}

// allLocalesExpr returns a JS expression that is true when all locales
// match the given state (all enabled or all disabled).
func allLocalesExpr(data DataIndex, enabled bool) string {
	var b []byte
	for i, c := range data.Catalogs {
		if i > 0 {
			b = append(b, "&&"...)
		}
		if !enabled {
			b = append(b, '!')
		}
		b = append(b, "$showlocales."...)
		b = append(b, c.Locale...)
	}
	return string(b)
}

func initShowDomainsSignal(data DataIndex) string {
	var b []byte
	b = append(b, '{')
	for i, d := range data.Domains {
		if i > 0 {
			b = append(b, ',')
		}
		b = append(b, d.SignalKey...)
		b = append(b, ':')
		if data.ShownDomains == nil {
			b = append(b, "true"...)
		} else if data.ShownDomains[d.FullName] {
			b = append(b, "true"...)
		} else {
			b = append(b, "false"...)
		}
	}
	b = append(b, '}')
	return string(b)
}

func setAllDomains(data DataIndex, enabled bool) string {
	val := "false"
	if enabled {
		val = "true"
	}
	var b []byte
	for _, d := range data.Domains {
		b = append(b, "$showdomains."...)
		b = append(b, d.SignalKey...)
		b = append(b, '=')
		b = append(b, val...)
		b = append(b, ';')
	}
	b = append(b, "$showndomains='"...)
	if enabled {
		for i, d := range data.Domains {
			if i > 0 {
				b = append(b, ',')
			}
			b = append(b, d.FullName...)
		}
	} else {
		b = append(b, '-')
	}
	b = append(b, '\'')
	return string(b)
}

func allDomainsExpr(data DataIndex, enabled bool) string {
	var b []byte
	for i, d := range data.Domains {
		if i > 0 {
			b = append(b, "&&"...)
		}
		if !enabled {
			b = append(b, '!')
		}
		b = append(b, "$showdomains."...)
		b = append(b, d.SignalKey...)
	}
	return string(b)
}

// allLocalesInitial evaluates the initial server-side state for the locale
// Hide All / Show All buttons so the disabled attribute matches before Datastar runs.
func allLocalesInitial(data DataIndex, enabled bool) bool {
	for _, c := range data.Catalogs {
		shown := data.ShownLocales == nil || data.ShownLocales[c.Locale]
		if shown != enabled {
			return false
		}
	}
	return true
}

// allDomainsInitial evaluates the initial server-side state for the domain
// Hide All / Show All buttons so the disabled attribute matches before Datastar runs.
func allDomainsInitial(data DataIndex, enabled bool) bool {
	for _, d := range data.Domains {
		shown := data.ShownDomains == nil || data.ShownDomains[d.FullName]
		if shown != enabled {
			return false
		}
	}
	return true
}

func tikChangedCount(tk *TIK) int {
	n := 0
	for _, m := range tk.ICU {
		if m.Changed {
			n++
		}
	}
	return n
}

